"use strict";parserFactory.register("randomtranslator.com",()=>new RandomtranslatorParser);class RandomtranslatorParser extends Parser{constructor(){super()}async getChapterUrls(t){let e=new RegExp("/novel/.+"),r=t.baseURI.match(e)?.[0].slice(7);return[...(await HttpClient.fetchJson("https://api.randomtranslator.com/api/v1/novels/"+r)).json.chapters].sort((t,e)=>t.sequence_number-e.sequence_number).map(t=>({sourceUrl:"https://www.randomtranslator.com/chapter/"+t.id,title:t.translated_title,isIncludeable:!t.is_restricted}))}async loadEpubMetaInfo(t){let e=new RegExp("/novel/.+"),r=t.baseURI.match(e)?.[0].slice(7),a=(await HttpClient.fetchJson("https://api.randomtranslator.com/api/v1/novels/"+r)).json;this.title=a.translated_title,this.author=a.translated_author,this.tags=a.tags.map(t=>t.translated_name),this.tags=this.tags.concat(a.translated_category),this.description=a.ai_description,this.img=a.image_url}extractTitleImpl(){return this.title}extractAuthor(){return this.author}extractSubject(){return this.tags.join(", ")}extractDescription(){return this.description.trim()}findCoverImageUrl(){return this.img}findContent(t){return Parser.findConstrutedContent(t)}async fetchChapter(t){let e=this.toRestUrl(t),r=(await HttpClient.fetchJson(e)).json;return this.buildChapter(r,t)}toRestUrl(t){let e=t.split("/");return"https://api.randomtranslator.com/api/v1/chapters/"+e[e.length-1]}buildChapter(t,e){let r=Parser.makeEmptyDocForContent(e),a=r.dom.createElement("h1");a.textContent=t.translated_title,r.content.appendChild(a);let n=t.translated_content.replace("\n\n","\n");n=n.split("\n");let s=r.dom.createElement("br");for(let t of n){let e=r.dom.createElement("p");e.textContent=t,r.content.appendChild(e),r.content.appendChild(s)}return r.dom}}